import api from './api';

export const cartService = {
  createCart: async (cart) => (await api.post('/carts', cart)).data,
  getAllCarts: async () => (await api.get('/carts')).data,
  getCartById: async (id) => (await api.get(`/carts/${id}`)).data,
  getCartByUserId: async (userId) => (await api.get(`/carts/user/${userId}`)).data,
  updateCart: async (id, cart) => (await api.put(`/carts/${id}`, cart)).data,
  deleteCart: async (id) => (await api.delete(`/carts/${id}`)).data,
};
